fn set_direct_path_cooldown(
    stats: &mut RuntimeStats,
    key: String,
    cooldown: Duration,
    reason_key: &'static str,
    gate_profit_pct: f64,
) {
    stats.direct_path_cooldowns.insert(
        key,
        DirectPathCooldownState {
            cooldown_until: Instant::now() + cooldown,
            reason_key,
            last_gate_profit_pct: gate_profit_pct,
        },
    );
}

